### Lightning Web Components (LWC)

```javascript
// Component folders/names - camelCase (Salesforce converts to kebab-case)
accountSummary/
opportunityList/
navigationMenu/
customDataTable/

// Component files follow folder name
accountSummary.html
accountSummary.js
accountSummary.css
accountSummary.js-meta.xml

// JavaScript - follow standard JS conventions
export default class AccountSummary extends LightningElement {

    // Private properties - prefix with underscore
    _accountId;

    // Public properties/attributes - @api decorator
    @api recordId;
    @api objectApiName;

    // Tracked properties
    @track accountData = {};

    // Wire properties
    @wire(getAccount, { accountId: '$recordId' })
    wiredAccount;

    // Constants - UPPER_SNAKE_CASE
    MAX_RECORDS = 100;
    DEFAULT_STATUS = 'Active';

    // Methods - camelCase verbs
    handleSave() {}
    handleCancel() {}
    fetchAccountData() {}

    // Getters - camelCase nouns
    get isLoading() {}
    get formattedName() {}

    // Lifecycle hooks - use standard names
    connectedCallback() {}
    disconnectedCallback() {}
    renderedCallback() {}
}

// Events - kebab-case when dispatching
this.dispatchEvent(new CustomEvent('accountsaved'));
this.dispatchEvent(new CustomEvent('statuschange'));
```

